import unittest

class TestSolution(unittest.TestCase):
    def test_insert_middle(self):
        self.assertEqual(insertion_sort_step([2, 5, 8, 3, 9], 3), [2, 3, 5, 8, 9])

    def test_insert_beginning(self):
        self.assertEqual(insertion_sort_step([4, 1], 1), [1, 4])

    def test_already_in_place(self):
        self.assertEqual(insertion_sort_step([3, 7, 10, 12], 3), [3, 7, 10, 12])

    def test_hidden_single_card(self):
        self.assertEqual(insertion_sort_step([5], 0), [5])

    def test_hidden_insert_to_front(self):
        self.assertEqual(insertion_sort_step([5, 5, 5, 3], 3), [3, 5, 5, 5])

    def test_hidden_sorted_no_change(self):
        self.assertEqual(insertion_sort_step([1, 2, 3, 4, 5], 4), [1, 2, 3, 4, 5])

    def test_hidden_reverse_step(self):
        self.assertEqual(insertion_sort_step([10, 7, 3, 1], 1), [7, 10, 3, 1])

    def test_hidden_insert_into_sorted_prefix(self):
        self.assertEqual(insertion_sort_step([1, 3, 5, 2], 3), [1, 2, 3, 5])

    def test_hidden_equal_values(self):
        self.assertEqual(insertion_sort_step([3, 3, 3, 3], 2), [3, 3, 3, 3])

    def test_hidden_index_zero(self):
        self.assertEqual(insertion_sort_step([7, 2, 9], 0), [7, 2, 9])

if __name__ == '__main__':
    unittest.main()
